// DNASAMPLE.ACCOUNT-INQUIRY -- marketplace demo script.
// Simulates a Fiserv DNA account inquiry. In a real deployment, replace the
// simulated section with a call to your DNA API using the connection named in
// the solution's required credentials, with its base URL taken from the
// #DNASAMPLE.DNA-BASE-URL variable.
def acct = 'DEMO-0001'
jobInfo.getArgs().each { a -> if (a.name == 'ACCOUNT_ID') { acct = a.argValue } }
println 'DNA sample: account inquiry for ' + acct + ' (simulated)'
println 'DNA sample: replace this body with your DNA API call'
statusCode = "0"

// DNASAMPLE.TXN-EXTRACT -- marketplace demo script.
// Simulates a Fiserv DNA transaction extract for a business date. In a real
// deployment, replace the simulated section with your DNA extract call and
// write the results wherever your downstream expects them.
def bizDate = 'TODAY'
jobInfo.getArgs().each { a -> if (a.name == 'BUSINESS_DATE') { bizDate = a.argValue } }
println 'DNA sample: transaction extract for ' + bizDate + ' (simulated)'
statusCode = "0"
